 1	import React, { FC } from 'react';
 2	import { VirtualMachineModel } from 'src/views/dashboard-extensions/utils';
 3	
 4	import SearchItem from '@kubevirt-utils/components/SearchItem/SearchItem';
 5	import SidebarEditor from '@kubevirt-utils/components/SidebarEditor/SidebarEditor';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { asAccessReview } from '@kubevirt-utils/resources/shared';
 8	import { PATHS_TO_HIGHLIGHT } from '@kubevirt-utils/resources/vm/utils/constants';
 9	import { K8sVerb, useAccessReview } from '@openshift-console/dynamic-plugin-sdk';
10	import {
11	  DescriptionList,
12	  Divider,
13	  PageSection,
14	  PageSectionVariants,
15	  Title,
16	} from '@patternfly/react-core';
17	
18	import { onSubmitYAML } from '../details/utils/utils';
19	import { ConfigurationInnerTabProps } from '../utils/types';
20	
21	import InitialRunTabCloudinit from './components/InitialRunTabCloudinit';
22	import InitialRunTabSysprep from './components/InitialRunTabSysprep';
23	
24	const InitialRunTab: FC<ConfigurationInnerTabProps> = ({ vm, vmi }) => {
25	  const { t } = useKubevirtTranslation();
26	  const accessReview = asAccessReview(VirtualMachineModel, vm, 'update' as K8sVerb);
27	  const [canUpdateVM] = useAccessReview(accessReview || {});
28	
29	  return (
30	    <SidebarEditor
31	      onResourceUpdate={onSubmitYAML}
32	      pathsToHighlight={PATHS_TO_HIGHLIGHT.SCRIPTS_TAB}
33	      resource={vm}
34	    >
35	      {(resource) => (
36	        <PageSection variant={PageSectionVariants.light}>
37	          <Title headingLevel="h2">
38	            <SearchItem id="initial-run">{t('Initial run')}</SearchItem>
39	          </Title>
40	          <DescriptionList className="pf-v6-c-description-list">
41	            <InitialRunTabCloudinit
42	              canUpdateVM={canUpdateVM}
43	              onSubmit={onSubmitYAML}
44	              vm={resource}
45	              vmi={vmi}
46	            />
47	            <Divider />
48	            <InitialRunTabSysprep canUpdateVM={canUpdateVM} vm={resource} />
49	          </DescriptionList>
50	        </PageSection>
51	      )}
52	    </SidebarEditor>
53	  );
54	};
55	
56	export default InitialRunTab;

